; 愚者の倉庫

name = 愚者の倉庫２
insideName = Floor 2
level = 23
bgm = trick
shadow = dark
sky = black
roof = stone
blank = rock
outfield = marble
antiWarp = true

; 各パーツ
━ = stone
　 = marble
☆ = soilr
❑ = cube
／ = door
⧻ = fence
☖ = arch
☗ = gate
︻ = panel

; 移動ポイント
(A) = map:愚者の倉庫１, x:8, y:3, way:w, symbol:exit, ask:Go to the previous floor?
(B) = map:愚者の倉庫３, x:10, y:7, way:s, symbol:exit, ask:Go to the next floor?

; 宝箱
box[1] = 罠はない,エクストラヒールの魔法書_u,エルフの弓_u,復活の粉,金貨（特大）

